import React, { useState } from 'react';

// High-resolution images gathered via autonomous search
const burgerImg = 'https://www.ketofocus.com/wp-content/uploads/juicy-lucy-burger-1-800x600.jpg';
const friesImg = 'https://i5.walmartimages.com/asr/46737801-9f16-4b68-ba4a-a334086724a4.14b80354186144602da507413a6639ea.jpeg?odnHeight=768&odnWidth=768&odnBg=FFFFFF';
const colaImg = 'https://media.istockphoto.com/id/530428650/photo/cola-glass-with-ice-cubes.jpg?s=612x612&w=0&k=20&c=keqH2KNWHO1sFxtsBfx5EZjyep1CRBHIqwe_ZwxszHc=';
const heroImg = 'https://i.pinimg.com/564x/c9/e5/ef/c9e5ef3ded2f824f35f89e68f08bef9c.jpg';

// Domain model for a menu item
interface MenuItem {
  id: number;
  name: string;
  description: string;
  price: number;
  img: string;
}

// Core catalog (could come from API in real product)
const menu: MenuItem[] = [
  {
    id: 1,
    name: 'Cheeseburger',
    description: 'Juicy beef patty with melted cheese, pickles and our signature sauce.',
    price: 4.99,
    img: burgerImg,
  },
  {
    id: 2,
    name: 'French Fries',
    description: 'Golden crispy fries with just the right amount of salt.',
    price: 2.49,
    img: friesImg,
  },
  {
    id: 3,
    name: 'Cola',
    description: 'Refreshing cold soda served with ice.',
    price: 1.99,
    img: colaImg,
  },
];

export default function App() {
  const [cart, setCart] = useState<{ item: MenuItem; qty: number }[]>([]);

  // Add or increment item in cart
  const addToCart = (item: MenuItem) => {
    setCart((prev) => {
      const existing = prev.find((c) => c.item.id === item.id);
      if (existing) {
        return prev.map((c) =>
          c.item.id === item.id ? { ...c, qty: c.qty + 1 } : c,
        );
      }
      return [...prev, { item, qty: 1 }];
    });
  };

  const total = cart
    .reduce((sum, c) => sum + c.item.price * c.qty, 0)
    .toFixed(2);

  return (
    <div
      style={{
        fontFamily: 'system-ui, sans-serif',
        margin: 0,
        padding: 0,
        background: '#fff',
        color: '#222',
      }}
    >
      {/* Hero / Header */}
      <header
        style={{
          position: 'relative',
          textAlign: 'center',
          color: '#fff',
        }}
      >
        <img
          src={heroImg}
          alt="Fast food restaurant interior"
          style={{ width: '100%', maxHeight: 300, objectFit: 'cover' }}
        />
        <h1
          style={{
            position: 'absolute',
            top: '50%',
            left: '50%',
            transform: 'translate(-50%, -50%)',
            margin: 0,
            fontSize: 48,
            textShadow: '0 0 10px rgba(0,0,0,0.5)',
          }}
        >
          FastBite
        </h1>
      </header>

      {/* Menu Grid */}
      <section style={{ padding: '2rem 1rem', maxWidth: 1000, margin: '0 auto' }}>
        <h2 style={{ textAlign: 'center', marginBottom: 32 }}>Menu</h2>
        <div
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(auto-fill, minmax(240px, 1fr))',
            gap: 24,
          }}
        >
          {menu.map((item) => (
            <div
              key={item.id}
              style={{
                border: '1px solid #eee',
                borderRadius: 8,
                overflow: 'hidden',
                boxShadow: '0 2px 6px rgba(0,0,0,0.05)',
              }}
            >
              <img
                src={item.img}
                alt={item.name}
                style={{ width: '100%', height: 160, objectFit: 'cover' }}
              />
              <div style={{ padding: 16 }}>
                <h3 style={{ margin: '0 0 8px' }}>{item.name}</h3>
                <p style={{ fontSize: 14, margin: '0 0 8px', color: '#555' }}>
                  {item.description}
                </p>
                <div
                  style={{
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'space-between',
                  }}
                >
                  <span style={{ fontWeight: 600 }}>${item.price.toFixed(2)}</span>
                  <button
                    onClick={() => addToCart(item)}
                    style={{
                      background: '#ffcb05',
                      border: 0,
                      padding: '6px 12px',
                      borderRadius: 4,
                      cursor: 'pointer',
                    }}
                  >
                    Add to Cart
                  </button>
                </div>
              </div>
            </div>
          ))}
        </div>
      </section>

      {/* Cart */}
      <aside
        style={{
          background: '#f8f8f8',
          padding: '2rem 1rem',
          borderTop: '1px solid #eee',
        }}
      >
        <div style={{ maxWidth: 600, margin: '0 auto' }}>
          <h2 style={{ textAlign: 'center', marginBottom: 24 }}>Your Order</h2>
          {cart.length === 0 && (
            <p style={{ textAlign: 'center', color: '#666' }}>Your cart is empty</p>
          )}
          {cart.map((c) => (
            <div
              key={c.item.id}
              style={{
                display: 'flex',
                justifyContent: 'space-between',
                marginBottom: 8,
              }}
            >
              <span>
                {c.item.name} × {c.qty}
              </span>
              <span>${(c.item.price * c.qty).toFixed(2)}</span>
            </div>
          ))}
          {cart.length > 0 && (
            <div
              style={{
                display: 'flex',
                justifyContent: 'space-between',
                fontWeight: 600,
                marginTop: 16,
              }}
            >
              <span>Total:</span>
              <span>${total}</span>
            </div>
          )}
        </div>
      </aside>

      {/* Footer */}
      <footer
        style={{
          textAlign: 'center',
          padding: '1rem 0',
          fontSize: 14,
          background: '#222',
          color: '#fff',
        }}
      >
        © {new Date().getFullYear()} FastBite. All rights reserved.
      </footer>
    </div>
  );
}
